INSERT INTO public.essay_prompts (title, college_name, how_many, selection_type, prompt_number, prompt, word_limit, prompt_selection_type, school_program_type) VALUES ('Common Application - Prompt 1', 'Common Application', 'one', 'choose_one', '1', 'The essay demonstrates your ability to write clearly and concisely on a selected topic and helps you distinguish yourself in your own voice. What do you want the readers of your application to know about you apart from courses, grades, and test scores? Choose the option that best helps you answer that question and write an essay of no more than 650 words, using the prompt to inspire and structure your response. Remember: 650 words is your limit, not your goal. Use the full range if you need it, but don''t feel obligated to do so. (The application won''t accept a response shorter than 250 words.)
INSERT INTO public.essay_prompts (title, college_name, how_many, selection_type, prompt_number, prompt, word_limit, prompt_selection_type, school_program_type) VALUES ('Common Application - Prompt 2', 'Common Application', 'one', 'choose_one', '2', 'The essay demonstrates your ability to write clearly and concisely on a selected topic and helps you distinguish yourself in your own voice. What do you want the readers of your application to know about you apart from courses, grades, and test scores? Choose the option that best helps you answer that question and write an essay of no more than 650 words, using the prompt to inspire and structure your response. Remember: 650 words is your limit, not your goal. Use the full range if you need it, but don''t feel obligated to do so. (The application won''t accept a response shorter than 250 words.)
