INSERT INTO public.essay_prompts (title, college_name, how_many, selection_type, prompt_number, prompt, word_limit, prompt_selection_type, school_program_type) VALUES ('Common Application - Prompt 5', 'Common Application', 'one', 'choose_one', '5', 'The essay demonstrates your ability to write clearly and concisely on a selected topic and helps you distinguish yourself in your own voice. What do you want the readers of your application to know about you apart from courses, grades, and test scores? Choose the option that best helps you answer that question and write an essay of no more than 650 words, using the prompt to inspire and structure your response. Remember: 650 words is your limit, not your goal. Use the full range if you need it, but don''t feel obligated to do so. (The application won''t accept a response shorter than 250 words.)
INSERT INTO public.essay_prompts (title, college_name, how_many, selection_type, prompt_number, prompt, word_limit, prompt_selection_type, school_program_type) VALUES ('Common Application - Prompt 6', 'Common Application', 'one', 'choose_one', '6', 'The essay demonstrates your ability to write clearly and concisely on a selected topic and helps you distinguish yourself in your own voice. What do you want the readers of your application to know about you apart from courses, grades, and test scores? Choose the option that best helps you answer that question and write an essay of no more than 650 words, using the prompt to inspire and structure your response. Remember: 650 words is your limit, not your goal. Use the full range if you need it, but don''t feel obligated to do so. (The application won''t accept a response shorter than 250 words.)
INSERT INTO public.essay_prompts (title, college_name, how_many, selection_type, prompt_number, prompt, word_limit, prompt_selection_type, school_program_type) VALUES ('Common Application - Prompt 7', 'Common Application', 'one', 'choose_one', '7', 'The essay demonstrates your ability to write clearly and concisely on a selected topic and helps you distinguish yourself in your own voice. What do you want the readers of your application to know about you apart from courses, grades, and test scores? Choose the option that best helps you answer that question and write an essay of no more than 650 words, using the prompt to inspire and structure your response. Remember: 650 words is your limit, not your goal. Use the full range if you need it, but don''t feel obligated to do so. (The application won''t accept a response shorter than 250 words.)
INSERT INTO public.essay_prompts (title, college_name, how_many, selection_type, prompt_number, prompt, word_limit, prompt_selection_type, school_program_type) VALUES ('Coalition Application - Prompt 1', 'Coalition Application', 'one', 'choose_one', '1', 'Tell a story from your life, describing an experience that either demonstrates your character or helped to shape it.', '500-650', 'choose_one', 'Undergraduate');
INSERT INTO public.essay_prompts (title, college_name, how_many, selection_type, prompt_number, prompt, word_limit, prompt_selection_type, school_program_type) VALUES ('Coalition Application - Prompt 2', 'Coalition Application', 'one', 'choose_one', '2', 'What interests or excites you? How does it shape who you are now or who you might become in the future?', '500-650', 'choose_one', 'Undergraduate');
INSERT INTO public.essay_prompts (title, college_name, how_many, selection_type, prompt_number, prompt, word_limit, prompt_selection_type, school_program_type) VALUES ('Coalition Application - Prompt 3', 'Coalition Application', 'one', 'choose_one', '3', 'Describe a time when you had a positive impact on others. What were the challenges? What were the rewards?', '500-650', 'choose_one', 'Undergraduate');
INSERT INTO public.essay_prompts (title, college_name, how_many, selection_type, prompt_number, prompt, word_limit, prompt_selection_type, school_program_type) VALUES ('Coalition Application - Prompt 4', 'Coalition Application', 'one', 'choose_one', '4', 'Has there been a time when an idea or belief of yours was questioned? How did you respond? What did you learn?', '500-650', 'choose_one', 'Undergraduate');
INSERT INTO public.essay_prompts (title, college_name, how_many, selection_type, prompt_number, prompt, word_limit, prompt_selection_type, school_program_type) VALUES ('Coalition Application - Prompt 5', 'Coalition Application', 'one', 'choose_one', '5', 'What success have you achieved or obstacle have you faced? What advice would you give a sibling or friend going through a similar experience?', '500-650', 'choose_one', 'Undergraduate');
INSERT INTO public.essay_prompts (title, college_name, how_many, selection_type, prompt_number, prompt, word_limit, prompt_selection_type, school_program_type) VALUES ('Coalition Application - Prompt 6', 'Coalition Application', 'one', 'choose_one', '6', 'Submit an essay on a topic of your choice', '500-650', 'choose_one', 'Undergraduate');
INSERT INTO public.essay_prompts (title, college_name, how_many, selection_type, prompt_number, prompt, word_limit, prompt_selection_type, school_program_type) VALUES ('American University - Prompt 1', 'American University', 'one', 'required', '1', 'American University students identify as changemakers and describe themselves as passionate. Describe a belief, hobby, idea, issue, or topic about which you''re excited.', '250', 'required', 'Undergraduate');
INSERT INTO public.essay_prompts (title, college_name, how_many, selection_type, prompt_number, prompt, word_limit, prompt_selection_type, school_program_type) VALUES ('Amherst College - Prompt Option A - Prompt 1', 'Amherst College', 'one', 'required', 'Option A - Prompt 1', 'What does curiosity mean to you? How do you experience curiosity in your own life?', '350', 'choose_one', 'Undergraduate');
INSERT INTO public.essay_prompts (title, college_name, how_many, selection_type, prompt_number, prompt, word_limit, prompt_selection_type, school_program_type) VALUES ('Amherst College - Prompt Option A - Prompt 2', 'Amherst College', 'one', 'required', 'Option A - Prompt 2', 'In what ways could your unique experiences enhance our understanding of our nation and our world?', '350', 'choose_one', 'Undergraduate');
INSERT INTO public.essay_prompts (title, college_name, how_many, selection_type, prompt_number, prompt, word_limit, prompt_selection_type, school_program_type) VALUES ('Amherst College - Prompt Option A - Prompt 3', 'Amherst College', 'one', 'required', 'Option A - Prompt 3', 'Tell us about a time that you engaged with a viewpoint different from your own. How did you enter that engagement, and what did you learn about yourself from it?', '350', 'choose_one', 'Undergraduate');
INSERT INTO public.essay_prompts (title, college_name, how_many, selection_type, prompt_number, prompt, word_limit, prompt_selection_type, school_program_type) VALUES ('Amherst College - Prompt Option B', 'Amherst College', 'one', 'required', 'Option B', 'Submit a graded paper from your junior or senior year that best represents your writing skills and analytical abilities. We are particularly interested in your ability to construct a tightly reasoned, persuasive argument that calls upon literary, sociological or historical evidence. You should not submit a laboratory report, journal entry, creative writing sample or in-class essay. Also, if you have submitted an analytical essay in response to the "essay topic of your choice" prompt in the Common Application or Apply Coalition with Scoir writing section, you should not select Option B.', 'Graded paper', 'choose_one', 'Undergraduate');
INSERT INTO public.essay_prompts (title, college_name, how_many, selection_type, prompt_number, prompt, word_limit, prompt_selection_type, school_program_type) VALUES ('Amherst College - Prompt Option C', 'Amherst College', 'one', 'required', 'Option C', 'If you are/were an applicant to Amherst''s Access to Amherst (A2A) program, you may use your A2A Writing Supplement essay in satisfaction of our supplementary essay requirement. If you would like to do so, please select Option C. However, if you would prefer not to use your A2A Writing Supplement for this purpose and you want to submit a different piece of writing, select either Option A or Option B. Option A, Prompt 2 is the same prompt as the A2A Writing Supplement essay; if you would like to submit an updated version of your A2A Writing Supplement essay, please choose Option A, Prompt 2. Please note that Option C is available only to applicants to Amherst''s A2A program. Non-A2A applicants must choose either Option A or Option B.', 'A2A essay', 'choose_one', 'Undergraduate');
INSERT INTO public.essay_prompts (title, college_name, how_many, selection_type, prompt_number, prompt, word_limit, prompt_selection_type, school_program_type) VALUES ('Babson College - Prompt 1', 'Babson College', 'all', 'required', '1', 'The Babson education prepares students for all types of careers across business, entrepreneurship, social innovation, and more. Tell us about your interest in this area of study and in Babson specifically.', '500', 'required', 'Undergraduate');
INSERT INTO public.essay_prompts (title, college_name, how_many, selection_type, prompt_number, prompt, word_limit, prompt_selection_type, school_program_type) VALUES ('Babson College - Prompt 2', 'Babson College', 'all', 'required', '2', 'A defining element of the Babson experience is learning and thriving in an equitable and inclusive community with a wide range of perspectives, experiences, and interests. Please share something about your background, lived experiences, or viewpoint(s) that speaks to: (1) your commitment to promoting access, connection, or understanding across differences; and/or (2) how you will contribute to and learn from Babson''s collaborative community.', '250', 'required', 'Undergraduate');
INSERT INTO public.essay_prompts (title, college_name, how_many, selection_type, prompt_number, prompt, word_limit, prompt_selection_type, school_program_type) VALUES ('Barnard College - Prompt 1', 'Barnard College', 'one', 'required', '1', 'Rooted in a history of trailblazing women, Barnard College is a collaborative community of care shaped by bold women with a multitude of perspectives. Choose one woman— historical, fictional, contemporary, or personally significant— whose views differ from your own. Imagine a conversation with her. What would you discuss? How might her perspective challenge or shift your own? Share how this new mindset could influence your approach to learning and engagement both in and beyond the classroom at Barnard.', '250', 'required', 'Undergraduate');
INSERT INTO public.essay_prompts (title, college_name, how_many, selection_type, prompt_number, prompt, word_limit, prompt_selection_type, school_program_type) VALUES ('Boston College - Prompt 1', 'Boston College', 'one', 'required', '1', 'Strong communities are sustained by traditions. Boston College''s annual calendar is marked with both long-standing and newer traditions that help shape our community. Tell us about a meaningful tradition in your family or community. Why is it important to you, and how does it bring people together or strengthen the bonds of those who participate?', '400', 'choose_one', 'Undergraduate');
INSERT INTO public.essay_prompts (title, college_name, how_many, selection_type, prompt_number, prompt, word_limit, prompt_selection_type, school_program_type) VALUES ('Boston College - Prompt 2', 'Boston College', 'one', 'required', '2', 'The late BC theology professor, Father Michael Himes, argued that a university is not a place to which you go, but instead, a "rigorous and sustained conversation about the great questions of human existence, among the widest possible circle of the best possible conversation partners." Who has been your most meaningful conversation partner, and what profound questions have you considered together?', '400', 'choose_one', 'Undergraduate');
INSERT INTO public.essay_prompts (title, college_name, how_many, selection_type, prompt_number, prompt, word_limit, prompt_selection_type, school_program_type) VALUES ('Boston College - Prompt 3', 'Boston College', 'one', 'required', '3', 'In her July 2009 Ted Talk, "The Danger of a Single Story," Chimamanda Ngozi Adichie warned viewers against assigning people a "single story" through assumptions about their nationality, appearance, or background. Discuss a time when someone defined you by a single story. What challenges did this present and how did you overcome them?', '400', 'choose_one', 'Undergraduate');
INSERT INTO public.essay_prompts (title, college_name, how_many, selection_type, prompt_number, prompt, word_limit, prompt_selection_type, school_program_type) VALUES ('Boston College - Prompt 4', 'Boston College', 'one', 'required', '4', 'Boston College''s Jesuit mission highlights "the three Be''s": be attentive, be reflective, be loving – core to Jesuit education (see A Pocket Guide to Jesuit Education). If you could add a fourth "Be," what would it be and why? How would this new value support your personal development and enrich the BC community?', '400', 'choose_one', 'Undergraduate');
INSERT INTO public.essay_prompts (title, college_name, how_many, selection_type, prompt_number, prompt, word_limit, prompt_selection_type, school_program_type) VALUES ('Boston College - Prompt 5', 'Boston College', 'one', 'required', '5', 'Human-Centered Engineering (HCE) Applicants only: One goal of a Jesuit education is to prepare students to serve the Common Good. Human-Centered Engineering at Boston College integrates technical knowledge, creativity, and a humanistic perspective to address societal challenges and opportunities. What societal problems are important to you and how will you use your HCE education to solve them?', '400', 'required', 'Undergraduate');
INSERT INTO public.essay_prompts (title, college_name, how_many, selection_type, prompt_number, prompt, word_limit, prompt_selection_type, school_program_type) VALUES ('Boston University - Prompt 1', 'Boston University', 'one', 'required', '1', 'Reflect on a social or community issue that deeply resonates with you. Why is it important to you, and how have you been involved in addressing or raising awareness about it?', '300', 'choose_one', 'Undergraduate');
INSERT INTO public.essay_prompts (title, college_name, how_many, selection_type, prompt_number, prompt, word_limit, prompt_selection_type, school_program_type) VALUES ('Boston University - Prompt 2', 'Boston University', 'one', 'required', '2', 'What about being a student at BU most excites you? How do you hope to contribute to our campus community', '300', 'choose_one', 'Undergraduate');
INSERT INTO public.essay_prompts (title, college_name, how_many, selection_type, prompt_number, prompt, word_limit, prompt_selection_type, school_program_type) VALUES ('Brandeis University - Prompt 1', 'Brandeis University', 'one', 'required', '1', 'What excites you the most about being an international student at Brandeis University?', '250', 'required', 'Undergraduate');
INSERT INTO public.essay_prompts (title, college_name, how_many, selection_type, prompt_number, prompt, word_limit, prompt_selection_type, school_program_type) VALUES ('Brown University - Prompt 1', 'Brown University', 'all', 'required', '1', 'Brown''s Open Curriculum allows students to explore broadly while also diving deeply into their academic pursuits. Tell us about any academic interests that excite you, and how you might pursue them at Brown.', '200-250', 'required', 'Undergraduate');
INSERT INTO public.essay_prompts (title, college_name, how_many, selection_type, prompt_number, prompt, word_limit, prompt_selection_type, school_program_type) VALUES ('Brown University - Prompt 2', 'Brown University', 'all', 'required', '2', 'Students entering Brown often find that making their home on College Hill naturally invites reflection on where they came from. Share how an aspect of your growing up has inspired or challenged you, and what unique contributions this might allow you to make to the Brown community.', '200-250', 'required', 'Undergraduate');
INSERT INTO public.essay_prompts (title, college_name, how_many, selection_type, prompt_number, prompt, word_limit, prompt_selection_type, school_program_type) VALUES ('Brown University - Prompt 3', 'Brown University', 'all', 'required', '3', 'Brown students care deeply about their work and the world around them. Students find contentment, satisfaction, and meaning in daily interactions and major discoveries. Whether big or small, mundane or spectacular, tell us about something that brings you joy.', '200-250', 'required', 'Undergraduate');
INSERT INTO public.essay_prompts (title, college_name, how_many, selection_type, prompt_number, prompt, word_limit, prompt_selection_type, school_program_type) VALUES ('Brown University - Prompt 4', 'Brown University', 'all', 'required', '4', 'What three words best describe you?', '3 words', 'required', 'Undergraduate');
INSERT INTO public.essay_prompts (title, college_name, how_many, selection_type, prompt_number, prompt, word_limit, prompt_selection_type, school_program_type) VALUES ('Brown University - Prompt 5', 'Brown University', 'all', 'required', '5', 'If you could teach a class on any one thing, whether academic or otherwise, what would it be?', '100', 'required', 'Undergraduate');
INSERT INTO public.essay_prompts (title, college_name, how_many, selection_type, prompt_number, prompt, word_limit, prompt_selection_type, school_program_type) VALUES ('Brown University - Prompt 6', 'Brown University', 'all', 'required', '6', 'In one sentence, Why Brown?', '50', 'required', 'Undergraduate');
INSERT INTO public.essay_prompts (title, college_name, how_many, selection_type, prompt_number, prompt, word_limit, prompt_selection_type, school_program_type) VALUES ('Bryn Mawr College - Prompt 1', 'Bryn Mawr College', 'one', 'required', '1', 'Why are you interested in Bryn Mawr?', 'Not specified', 'required', 'Undergraduate');
INSERT INTO public.essay_prompts (title, college_name, how_many, selection_type, prompt_number, prompt, word_limit, prompt_selection_type, school_program_type) VALUES ('Bowdoin College - Prompt 1', 'Bowdoin College', 'one', 'required', '1', 'Generations of students have found connection and meaning in Bowdoin''s "The Offer of the College," written in 1906 by Bowdoin President William DeWitt Hyde.
INSERT INTO public.essay_prompts (title, college_name, how_many, selection_type, prompt_number, prompt, word_limit, prompt_selection_type, school_program_type) VALUES ('Caltech - Prompt 1', 'Caltech', 'all', 'required', '1', 'Your STEM Future – STEM Academic Interests
INSERT INTO public.essay_prompts (title, college_name, how_many, selection_type, prompt_number, prompt, word_limit, prompt_selection_type, school_program_type) VALUES ('Caltech - Prompt 2', 'Caltech', 'all', 'required', '2', 'Your STEM Present – STEM Curiosity
INSERT INTO public.essay_prompts (title, college_name, how_many, selection_type, prompt_number, prompt, word_limit, prompt_selection_type, school_program_type) VALUES ('Caltech - Prompt 3', 'Caltech', 'all', 'required', '3', 'Your STEM Past – STEM Experiences
INSERT INTO public.essay_prompts (title, college_name, how_many, selection_type, prompt_number, prompt, word_limit, prompt_selection_type, school_program_type) VALUES ('Caltech - Prompt 4', 'Caltech', 'all', 'required', '4', 'Creativity in Action Question
INSERT INTO public.essay_prompts (title, college_name, how_many, selection_type, prompt_number, prompt, word_limit, prompt_selection_type, school_program_type) VALUES ('Caltech - Prompt 5', 'Caltech', 'all', 'required', '5', 'Choose two of the four questions below and answer both in 250 words or less.
INSERT INTO public.essay_prompts (title, college_name, how_many, selection_type, prompt_number, prompt, word_limit, prompt_selection_type, school_program_type) VALUES ('Caltech - Prompt 6', 'Caltech', 'all', 'required', '6', 'OPTIONAL: Have you had any extenuating circumstances (such as limited course selection or disruptions), that have affected your coursework, but that are not described elsewhere in your application? If so, tell us about them here.', 'Not specified', 'optional', 'Undergraduate');
INSERT INTO public.essay_prompts (title, college_name, how_many, selection_type, prompt_number, prompt, word_limit, prompt_selection_type, school_program_type) VALUES ('Carnegie Mellon University - Prompt 1', 'Carnegie Mellon University', 'all', 'required', '1', 'Most students choose their intended major or area of study based on a passion or inspiration that''s developed over time – what passion or inspiration led you to choose this area of study?', '300', 'required', 'Undergraduate');
INSERT INTO public.essay_prompts (title, college_name, how_many, selection_type, prompt_number, prompt, word_limit, prompt_selection_type, school_program_type) VALUES ('Carnegie Mellon University - Prompt 2', 'Carnegie Mellon University', 'all', 'required', '2', 'Many students pursue college for a specific degree, career opportunity or personal goal. Whichever it may be, learning will be critical to achieve your ultimate goal. As you think ahead to the process of learning during your college years, how will you define a successful college experience?', '300', 'required', 'Undergraduate');
INSERT INTO public.essay_prompts (title, college_name, how_many, selection_type, prompt_number, prompt, word_limit, prompt_selection_type, school_program_type) VALUES ('Carnegie Mellon University - Prompt 3', 'Carnegie Mellon University', 'all', 'required', '3', 'Consider your application as a whole. What do you personally want to emphasize about your application for the admission committee''s consideration? Highlight something that''s important to you or something you haven''t had a chance to share. Tell us, don''t show us (no websites please).', '300', 'required', 'Undergraduate');
INSERT INTO public.essay_prompts (title, college_name, how_many, selection_type, prompt_number, prompt, word_limit, prompt_selection_type, school_program_type) VALUES ('Chapman University - Prompt 1', 'Chapman University', 'all', 'required', '1', 'There are thousands of universities and colleges. Why are you interested in attending Chapman?', '200', 'required', 'Undergraduate');
INSERT INTO public.essay_prompts (title, college_name, how_many, selection_type, prompt_number, prompt, word_limit, prompt_selection_type, school_program_type) VALUES ('Chapman University - Prompt 2', 'Chapman University', 'all', 'required', '2', 'Fast Facts are a way for us to get to know you. We want to see who you are as a student and as a person! Feel free to be creative, but remember what we''re asking. Just because they''re "fast" doesn''t mean you shouldn''t put some thought into your answers. We spend a lot of time debating the merits of each Fast Fact and voting on our favorites. Seriously. Here''s a list of some of our past and current Fast Fact questions:
INSERT INTO public.essay_prompts (title, college_name, how_many, selection_type, prompt_number, prompt, word_limit, prompt_selection_type, school_program_type) VALUES ('Harvard University - Prompt 1', 'Harvard University', 'all', 'required', '1', 'Harvard has long recognized the importance of enrolling a student body with a diversity of perspectives and experiences. How will the life experiences that shaped who you are today enable you to contribute to Harvard?', '100', 'required', 'Undergraduate');
INSERT INTO public.essay_prompts (title, college_name, how_many, selection_type, prompt_number, prompt, word_limit, prompt_selection_type, school_program_type) VALUES ('Harvard University - Prompt 2', 'Harvard University', 'all', 'required', '2', 'Describe a time when you strongly disagreed with someone about an idea or issue. How did you communicate or engage with this person? What did you learn from this experience?', '100', 'required', 'Undergraduate');
INSERT INTO public.essay_prompts (title, college_name, how_many, selection_type, prompt_number, prompt, word_limit, prompt_selection_type, school_program_type) VALUES ('Harvard University - Prompt 3', 'Harvard University', 'all', 'required', '3', 'Briefly describe any of your extracurricular activities, employment experience, travel, or family responsibilities that have shaped who you are.', '100', 'required', 'Undergraduate');
INSERT INTO public.essay_prompts (title, college_name, how_many, selection_type, prompt_number, prompt, word_limit, prompt_selection_type, school_program_type) VALUES ('Harvard University - Prompt 4', 'Harvard University', 'all', 'required', '4', 'How do you hope to use your Harvard education in the future?', '100', 'required', 'Undergraduate');
INSERT INTO public.essay_prompts (title, college_name, how_many, selection_type, prompt_number, prompt, word_limit, prompt_selection_type, school_program_type) VALUES ('Harvard University - Prompt 5', 'Harvard University', 'all', 'required', '5', 'Top 3 things your roommates might like to know about you.', '100', 'required', 'Undergraduate');
INSERT INTO public.essay_prompts (title, college_name, how_many, selection_type, prompt_number, prompt, word_limit, prompt_selection_type, school_program_type) VALUES ('Yale University - Prompt 1', 'Yale University', 'all', 'required', '1', 'Students at Yale have time to explore their academic interests before committing to one or more major fields of study. Many students either modify their original academic direction or change their minds entirely. As of this moment, what academic areas seem to fit your interests or goals most comfortably? Please indicate up to three from the list provided.', 'Not specified', 'required', 'Undergraduate');
INSERT INTO public.essay_prompts (title, college_name, how_many, selection_type, prompt_number, prompt, word_limit, prompt_selection_type, school_program_type) VALUES ('Yale University - Prompt 2', 'Yale University', 'all', 'required', '2', 'Tell us about a topic or idea that excites you and is related to one or more academic areas you selected above. Why are you drawn to it?', '200', 'required', 'Undergraduate');
INSERT INTO public.essay_prompts (title, college_name, how_many, selection_type, prompt_number, prompt, word_limit, prompt_selection_type, school_program_type) VALUES ('Yale University - Prompt 3', 'Yale University', 'all', 'required', '3', 'Reflect on how your interests, values, and/or experiences have drawn you to Yale.', '125', 'required', 'Undergraduate');
INSERT INTO public.essay_prompts (title, college_name, how_many, selection_type, prompt_number, prompt, word_limit, prompt_selection_type, school_program_type) VALUES ('Yale University - Prompt 4', 'Yale University', 'all', 'required', '4', 'What inspires you?', '200 characters', 'required', 'Undergraduate');
INSERT INTO public.essay_prompts (title, college_name, how_many, selection_type, prompt_number, prompt, word_limit, prompt_selection_type, school_program_type) VALUES ('Yale University - Prompt 5', 'Yale University', 'all', 'required', '5', 'If you could teach any college course, write a book, or create an original piece of art of any kind, what would it be?', '200 characters', 'required', 'Undergraduate');
INSERT INTO public.essay_prompts (title, college_name, how_many, selection_type, prompt_number, prompt, word_limit, prompt_selection_type, school_program_type) VALUES ('Yale University - Prompt 6', 'Yale University', 'all', 'required', '6', 'Other than a family member, who is someone who has had a significant influence on you? What has been the impact of their influence?', '200 characters', 'required', 'Undergraduate');
INSERT INTO public.essay_prompts (title, college_name, how_many, selection_type, prompt_number, prompt, word_limit, prompt_selection_type, school_program_type) VALUES ('Yale University - Prompt 7', 'Yale University', 'all', 'required', '7', 'What is something about you that is not included anywhere else in your application?', '200 characters', 'required', 'Undergraduate');
INSERT INTO public.essay_prompts (title, college_name, how_many, selection_type, prompt_number, prompt, word_limit, prompt_selection_type, school_program_type) VALUES ('Duke University - Prompt 1', 'Duke University', 'one', 'required', '1', 'What is your impression of Duke as a university and community, and why do you believe it is a good match for your goals, values, and interests? If there is something specific that attracts you to our academic offerings in Trinity College of Arts and Sciences or the Pratt School of Engineering, or to our co-curricular opportunities, feel free to include that too.', '250', 'required', 'Undergraduate');
INSERT INTO public.essay_prompts (title, college_name, how_many, selection_type, prompt_number, prompt, word_limit, prompt_selection_type, school_program_type) VALUES ('Duke University - Prompt 2', 'Duke University', 'one', 'required', '2', 'We believe a wide range of viewpoints and experiences is essential to maintaining Duke''s vibrant living and learning community. Please share anything in this context that might help us better understand you and your potential contributions to Duke.', '250', 'optional', 'Undergraduate');
INSERT INTO public.essay_prompts (title, college_name, how_many, selection_type, prompt_number, prompt, word_limit, prompt_selection_type, school_program_type) VALUES ('Duke University - Prompt 3', 'Duke University', 'one', 'required', '3', 'Meaningful dialogue often involves respectful disagreement. Provide an example of a difference of opinion you''ve had with someone you care about. What did you learn from it?', '250', 'optional', 'Undergraduate');
INSERT INTO public.essay_prompts (title, college_name, how_many, selection_type, prompt_number, prompt, word_limit, prompt_selection_type, school_program_type) VALUES ('Duke University - Prompt 4', 'Duke University', 'one', 'required', '4', 'What''s the last thing that you''ve been really excited about?', '250', 'optional', 'Undergraduate');
INSERT INTO public.essay_prompts (title, college_name, how_many, selection_type, prompt_number, prompt, word_limit, prompt_selection_type, school_program_type) VALUES ('Duke University - Prompt 5', 'Duke University', 'one', 'required', '5', 'Duke recently launched an initiative "to bring together Duke experts across all disciplines who are advancing AI research, addressing the most pressing ethical challenges posed by AI, and shaping the future of AI in the classroom." Tell us about a situation when you would or would not choose to use AI (when possible and permitted). What shapes your thinking?', '250', 'optional', 'Undergraduate');
INSERT INTO public.essay_prompts (title, college_name, how_many, selection_type, prompt_number, prompt, word_limit, prompt_selection_type, school_program_type) VALUES ('Northwestern University - Prompt 1', 'Northwestern University', 'one', 'required', '1', 'We want to be sure we''re considering your application in the context of your personal experiences: What aspects of your background (your identity, your school setting, your community, your household, etc.) have most shaped how you see yourself engaging in Northwestern''s community, be it academically, extracurricularly, culturally, politically, socially, or otherwise?', '300', 'required', 'Undergraduate');
INSERT INTO public.essay_prompts (title, college_name, how_many, selection_type, prompt_number, prompt, word_limit, prompt_selection_type, school_program_type) VALUES ('Northwestern University - Prompt 2a', 'Northwestern University', 'one', 'required', '2a', 'Painting "The Rock" is a tradition at Northwestern that invites all forms of expression—students promote campus events or extracurricular groups, support social or activist causes, show their Wildcat spirit (what we call "Purple Pride"), celebrate their culture, and more. What would you paint on The Rock, and why?', '200', 'choose_one', 'Undergraduate');
INSERT INTO public.essay_prompts (title, college_name, how_many, selection_type, prompt_number, prompt, word_limit, prompt_selection_type, school_program_type) VALUES ('Northwestern University - Prompt 2b', 'Northwestern University', 'one', 'required', '2b', 'Northwestern fosters a distinctively interdisciplinary culture. We believe discovery and innovation thrive at the intersection of diverse ideas, perspectives, and academic interests. Within this setting, if you could dream up an undergraduate class, research project, or creative effort (a start-up, a design prototype, a performance, etc.), what would it be? Who might be some ideal classmates or collaborators?', '200', 'choose_one', 'Undergraduate');
INSERT INTO public.essay_prompts (title, college_name, how_many, selection_type, prompt_number, prompt, word_limit, prompt_selection_type, school_program_type) VALUES ('Northwestern University - Prompt 2c', 'Northwestern University', 'one', 'required', '2c', 'Community and belonging matter at Northwestern. Tell us about one or more communities, networks, or student groups you see yourself connecting with on campus.', '200', 'choose_one', 'Undergraduate');
INSERT INTO public.essay_prompts (title, college_name, how_many, selection_type, prompt_number, prompt, word_limit, prompt_selection_type, school_program_type) VALUES ('Northwestern University - Prompt 2d', 'Northwestern University', 'one', 'required', '2d', 'Northwestern''s location is special: on the shore of Lake Michigan, steps from downtown Evanston, just a few miles from Chicago. What aspects of our location are most compelling to you, and why?', '200', 'choose_one', 'Undergraduate');
INSERT INTO public.essay_prompts (title, college_name, how_many, selection_type, prompt_number, prompt, word_limit, prompt_selection_type, school_program_type) VALUES ('Northwestern University - Prompt 2e', 'Northwestern University', 'one', 'required', '2e', 'Northwestern is a place where people with diverse backgrounds from all over the world can study, live, and talk with one another. This range of experiences and viewpoints immeasurably enriches learning. How might your individual background contribute to this diversity of perspectives in Northwestern''s classrooms and around our campus?', '200', 'choose_one', 'Undergraduate');
INSERT INTO public.essay_prompts (title, college_name, how_many, selection_type, prompt_number, prompt, word_limit, prompt_selection_type, school_program_type) VALUES ('University of Pennsylvania - Prompt 1', 'University of Pennsylvania', 'all', 'required', '1', 'Write a short thank-you note to someone you have not yet thanked and would like to acknowledge. (We encourage you to share this note with that person, if possible, and reflect on the experience!)', '150-200', 'required', 'Undergraduate');
INSERT INTO public.essay_prompts (title, college_name, how_many, selection_type, prompt_number, prompt, word_limit, prompt_selection_type, school_program_type) VALUES ('University of Pennsylvania - Prompt 2', 'University of Pennsylvania', 'all', 'required', '2', 'How will you explore community at Penn? Consider how Penn will help shape your perspective, and how your experiences and perspective will help shape Penn.', '150-200', 'required', 'Undergraduate');
INSERT INTO public.essay_prompts (title, college_name, how_many, selection_type, prompt_number, prompt, word_limit, prompt_selection_type, school_program_type) VALUES ('University of Pennsylvania - Prompt School of Nursing', 'University of Pennsylvania', 'all', 'required', 'School of Nursing', 'Penn Nursing intends to meet the health needs of society in a global and multicultural world by preparing its students to impact healthcare by advancing science. Why have you decided to apply to Nursing? Where do you see yourself professionally in the future and how will you contribute to our mission of promoting equity in healthcare?', '150-200', 'required', 'Undergraduate');
INSERT INTO public.essay_prompts (title, college_name, how_many, selection_type, prompt_number, prompt, word_limit, prompt_selection_type, school_program_type) VALUES ('University of Pennsylvania - Prompt College of Arts and Sciences', 'University of Pennsylvania', 'all', 'required', 'College of Arts and Sciences', 'The flexible structure of The College of Arts and Sciences'' curriculum is designed to inspire exploration, foster connections, and help you create a path of study through general education courses and a major. What are you curious about and how would you take advantage of opportunities in the arts and sciences?', '150-200', 'required', 'Undergraduate');
INSERT INTO public.essay_prompts (title, college_name, how_many, selection_type, prompt_number, prompt, word_limit, prompt_selection_type, school_program_type) VALUES ('University of Pennsylvania - Prompt The Wharton School', 'University of Pennsylvania', 'all', 'required', 'The Wharton School', 'Wharton prepares its students to make an impact by applying business methods and economic theory to real-world problems, including economic, political, and social issues. Please reflect on a current issue of importance to you and share how you hope a Wharton education would help you to explore it.', '150-200', 'required', 'Undergraduate');
INSERT INTO public.essay_prompts (title, college_name, how_many, selection_type, prompt_number, prompt, word_limit, prompt_selection_type, school_program_type) VALUES ('University of Pennsylvania - Prompt The School of Engineering and Applied Science', 'University of Pennsylvania', 'all', 'required', 'The School of Engineering and Applied Science', 'Penn Engineering prepares its students to become leaders in technology by combining a strong foundation in the natural sciences and mathematics with depth of study in focused disciplinary majors. Please share how you plan to pursue your engineering interests at Penn, particularly within the intended major you selected.', '150-200', 'required', 'Undergraduate');
INSERT INTO public.essay_prompts (title, college_name, how_many, selection_type, prompt_number, prompt, word_limit, prompt_selection_type, school_program_type) VALUES ('University of Pennsylvania - Prompt DMD: Digital Media Design Program', 'University of Pennsylvania', 'all', 'required', 'DMD: Digital Media Design Program', 'Discuss how your interests align with the Digital Media Design (DMD) program at the University of Pennsylvania?', '400-650', 'required', 'Undergraduate');
INSERT INTO public.essay_prompts (title, college_name, how_many, selection_type, prompt_number, prompt, word_limit, prompt_selection_type, school_program_type) VALUES ('University of Pennsylvania - Prompt Huntsman: Target Language', 'University of Pennsylvania', 'all', 'required', 'Huntsman: Target Language', 'Applicants to the Huntsman Program must choose one of eleven target languages. Please select your target language.
INSERT INTO public.essay_prompts (title, college_name, how_many, selection_type, prompt_number, prompt, word_limit, prompt_selection_type, school_program_type) VALUES ('University of Pennsylvania - Prompt Huntsman: Dual Degree', 'University of Pennsylvania', 'all', 'required', 'Huntsman: Dual Degree', 'The Huntsman Program supports the development of globally-minded scholars who become engaged citizens, creative innovators, and ethical leaders in the public, private, and non-profit sectors in the United States and around the world. What draws you to a dual degree in international studies and business, and how would you use what you learn to address a global issue where these two domains intersect?', '400-600', 'required', 'Undergraduate');
INSERT INTO public.essay_prompts (title, college_name, how_many, selection_type, prompt_number, prompt, word_limit, prompt_selection_type, school_program_type) VALUES ('University of Pennsylvania - Prompt LSM: Life Sciences and Management', 'University of Pennsylvania', 'all', 'required', 'LSM: Life Sciences and Management', 'The Vagelos Life Sciences & Management (LSM) program brings together two powerful modes of understanding—scientific inquiry and strategic thinking—to prepare students to engage thoughtfully and creatively with some of the most complex challenges of our time. Reflecting on this intersection, what questions, problems, or opportunities would you hope to explore through LSM? How might the integration of life sciences and management shape your approach to these challenges?
INSERT INTO public.essay_prompts (title, college_name, how_many, selection_type, prompt_number, prompt, word_limit, prompt_selection_type, school_program_type) VALUES ('University of Pennsylvania - Prompt M&T: Program Interest', 'University of Pennsylvania', 'all', 'required', 'M&T: Program Interest', 'Explain how you will use the M&T program to explore your interest in business, engineering, and the intersection of the two.', '400-650', 'required', 'Undergraduate');
INSERT INTO public.essay_prompts (title, college_name, how_many, selection_type, prompt_number, prompt, word_limit, prompt_selection_type, school_program_type) VALUES ('University of Pennsylvania - Prompt M&T: Leadership and Creativity', 'University of Pennsylvania', 'all', 'required', 'M&T: Leadership and Creativity', 'Describe a problem that you solved that showed leadership and creativity.', '250', 'required', 'Undergraduate');
INSERT INTO public.essay_prompts (title, college_name, how_many, selection_type, prompt_number, prompt, word_limit, prompt_selection_type, school_program_type) VALUES ('University of Pennsylvania - Prompt NHCM: Nursing and Healthcare Management', 'University of Pennsylvania', 'all', 'required', 'NHCM: Nursing and Healthcare Management', 'Discuss your interest in nursing and health care management. How might Penn''s coordinated dual-degree program in nursing and business help you meet your goals?', '400-650', 'required', 'Undergraduate');
INSERT INTO public.essay_prompts (title, college_name, how_many, selection_type, prompt_number, prompt, word_limit, prompt_selection_type, school_program_type) VALUES ('University of Pennsylvania - Prompt VIPER: Science and Engineering Majors', 'University of Pennsylvania', 'all', 'required', 'VIPER: Science and Engineering Majors', 'If you were to join the Vagelos Integrated Program in Energy Research (VIPER), which science major and which engineering major are most interesting to you at this time? You can learn more about available majors on our website.', 'Not specified', 'required', 'Undergraduate');
INSERT INTO public.essay_prompts (title, college_name, how_many, selection_type, prompt_number, prompt, word_limit, prompt_selection_type, school_program_type) VALUES ('University of Pennsylvania - Prompt VIPER: Energy Science and Technology', 'University of Pennsylvania', 'all', 'required', 'VIPER: Energy Science and Technology', 'How do you envision your participation in VIPER furthering your interests in energy science and technology? Please include any past experiences (ex. academic, research, or extracurricular) that have led to your interest in the program. Additionally, please indicate why you are interested in pursuing dual degrees in the VIPER majors listed above.', '400-650', 'required', 'Undergraduate');
INSERT INTO public.essay_prompts (title, college_name, how_many, selection_type, prompt_number, prompt, word_limit, prompt_selection_type, school_program_type) VALUES ('Columbia University - Prompt 1', 'Columbia University', 'all', 'required', '1', 'List a selection of texts, resources and outlets that have contributed to your intellectual development outside of academic courses, including but not limited to books, journals, websites, podcasts, essays, plays, presentations, videos, museums and other content that you enjoy.', '100', 'required', 'Undergraduate');
INSERT INTO public.essay_prompts (title, college_name, how_many, selection_type, prompt_number, prompt, word_limit, prompt_selection_type, school_program_type) VALUES ('Columbia University - Prompt 2', 'Columbia University', 'all', 'required', '2', 'Tell us about an aspect of your life so far or your lived experience that is important to you, and describe how it has shaped the way you would learn from and contribute to Columbia''s multidimensional and collaborative environment.', '150', 'required', 'Undergraduate');
INSERT INTO public.essay_prompts (title, college_name, how_many, selection_type, prompt_number, prompt, word_limit, prompt_selection_type, school_program_type) VALUES ('Columbia University - Prompt 3', 'Columbia University', 'all', 'required', '3', 'At Columbia, students representing a wide range of perspectives are invited to live and learn together. In such a community, questions and debates naturally arise. Please describe a time when you did not agree with someone and discuss how you engaged with them and what you took away from the interaction.', '150', 'required', 'Undergraduate');
INSERT INTO public.essay_prompts (title, college_name, how_many, selection_type, prompt_number, prompt, word_limit, prompt_selection_type, school_program_type) VALUES ('Columbia University - Prompt 4', 'Columbia University', 'all', 'required', '4', 'In college/university, students are often challenged in ways that they could not anticipate. Please describe a situation in which you have navigated through adversity and discuss how you changed as a result.', '150', 'required', 'Undergraduate');
INSERT INTO public.essay_prompts (title, college_name, how_many, selection_type, prompt_number, prompt, word_limit, prompt_selection_type, school_program_type) VALUES ('Columbia University - Prompt 5', 'Columbia University', 'all', 'required', '5', 'Why are you interested in attending Columbia University? We encourage you to consider the aspect(s) that you find unique and compelling about Columbia.', '150', 'required', 'Undergraduate');
INSERT INTO public.essay_prompts (title, college_name, how_many, selection_type, prompt_number, prompt, word_limit, prompt_selection_type, school_program_type) VALUES ('Columbia University - Prompt Columbia College', 'Columbia University', 'all', 'required', 'Columbia College', 'What attracts you to your preferred areas of study at Columbia College?', '150', 'required', 'Undergraduate');
INSERT INTO public.essay_prompts (title, college_name, how_many, selection_type, prompt_number, prompt, word_limit, prompt_selection_type, school_program_type) VALUES ('Columbia University - Prompt Columbia Engineering', 'Columbia University', 'all', 'required', 'Columbia Engineering', 'What attracts you to your preferred areas of study at Columbia Engineering?', '150', 'required', 'Undergraduate');
INSERT INTO public.essay_prompts (title, college_name, how_many, selection_type, prompt_number, prompt, word_limit, prompt_selection_type, school_program_type) VALUES ('Cornell University - Prompt 1', 'Cornell University', 'all', 'required', '1', 'We all contribute to, and are influenced by, the communities that are meaningful to us. Share how you''ve been shaped by one of the communities you belong to.
INSERT INTO public.essay_prompts (title, college_name, how_many, selection_type, prompt_number, prompt, word_limit, prompt_selection_type, school_program_type) VALUES ('Cornell University - Prompt College of Agriculture and Life Sciences', 'Cornell University', 'all', 'required', 'College of Agriculture and Life Sciences', 'By applying to Cornell''s College of Agriculture and Life Sciences (CALS), you are also applying for direct entry into one of our 20+ majors. From here, you would be part of a community dedicated to purpose-driven science; working within your major and across disciplines to tackle the complex challenges of our time.
INSERT INTO public.essay_prompts (title, college_name, how_many, selection_type, prompt_number, prompt, word_limit, prompt_selection_type, school_program_type) VALUES ('Cornell University - Prompt CALS Optional 1', 'Cornell University', 'all', 'required', 'CALS Optional 1', 'At Cornell CALS, we aim to leave the world better than we found it, so we seek out those who are passionate about serving the public good. Please elaborate on an experience where you were able to have a meaningful impact on people, a community, and/or an environment of importance to you.', '100', 'optional', 'Undergraduate');
INSERT INTO public.essay_prompts (title, college_name, how_many, selection_type, prompt_number, prompt, word_limit, prompt_selection_type, school_program_type) VALUES ('Cornell University - Prompt CALS Optional 2', 'Cornell University', 'all', 'required', 'CALS Optional 2', 'Given our agricultural history and commitment to educating the next generation of agriculturalists, please share if you have a background or interest in agriculture, regardless of your intended major. An "agricultural entity" for the purpose of this question is defined as cultivating soil, growing crops, and raising livestock (e.g., farm, ranch, greenhouse, vineyard, etc.)
INSERT INTO public.essay_prompts (title, college_name, how_many, selection_type, prompt_number, prompt, word_limit, prompt_selection_type, school_program_type) VALUES ('Cornell University - Prompt College of Architecture, Art, and Planning', 'Cornell University', 'all', 'required', 'College of Architecture, Art, and Planning', 'How do your interests directly connect with your intended major at the College of Architecture, Art, and Planning (AAP)? Why architecture (B.Arch), art (BFA), or urban and regional studies (URS)? B. Arch applicants, please provide an example of how a creative project or passion sparks your motivation to pursue a 5-year professional degree program. BFA applicants may want to to consider how they could integrate a range of interests and available resources at Cornell into a coherent art practice. URS students may want to emphasize their enthusiasm and depth of interest in the study of urban and regional issues.', '650', 'required', 'Undergraduate');
INSERT INTO public.essay_prompts (title, college_name, how_many, selection_type, prompt_number, prompt, word_limit, prompt_selection_type, school_program_type) VALUES ('Cornell University - Prompt College of Arts & Sciences', 'Cornell University', 'all', 'required', 'College of Arts & Sciences', 'At the College of Arts and Sciences, curiosity will be your guide. Discuss how your passion for learning is shaping your academic journey, and what areas of study or majors excite you and why. Your response should convey how your interests align with the College, and how you would take advantage of the opportunities and curriculum in Arts and Sciences.', '650', 'required', 'Undergraduate');
INSERT INTO public.essay_prompts (title, college_name, how_many, selection_type, prompt_number, prompt, word_limit, prompt_selection_type, school_program_type) VALUES ('Cornell University - Prompt Cornell Jeb E. Brooks School of Public Policy', 'Cornell University', 'all', 'required', 'Cornell Jeb E. Brooks School of Public Policy', 'Why are you interested in studying policy, and why do you want to pursue this major at Cornell''s Jeb E. Brooks School of Public Policy? You should share how your current interests, related experiences, and/or goals have influenced your choice of policy major.', 'Not specified', 'required', 'Undergraduate');
INSERT INTO public.essay_prompts (title, college_name, how_many, selection_type, prompt_number, prompt, word_limit, prompt_selection_type, school_program_type) VALUES ('Cornell University - Prompt Cornell SC Johnson College of Business', 'Cornell University', 'all', 'required', 'Cornell SC Johnson College of Business', 'What kind of a business student are you? Using your personal, academic, or volunteer/work experiences, describe the topics or issues that you care about and why they are important to you. Your response should convey how your interests align with the school to which you are applying within the Cornell SC Johnson College of Business (Charles H. Dyson School of Applied Economics and Management or the Cornell Peter and Stephanie Nolan School of Hotel Administration).', '650', 'required', 'Undergraduate');
INSERT INTO public.essay_prompts (title, college_name, how_many, selection_type, prompt_number, prompt, word_limit, prompt_selection_type, school_program_type) VALUES ('Cornell University - Prompt College of Engineering - Long Essay 1', 'Cornell University', 'all', 'required', 'College of Engineering - Long Essay 1', 'Fundamentally, engineering is the application of math, science, and technology to solve complex problems. Why do you want to study engineering?', '200', 'required', 'Undergraduate');
INSERT INTO public.essay_prompts (title, college_name, how_many, selection_type, prompt_number, prompt, word_limit, prompt_selection_type, school_program_type) VALUES ('Cornell University - Prompt College of Engineering - Long Essay 2', 'Cornell University', 'all', 'required', 'College of Engineering - Long Essay 2', 'Why do you think you would love to study at Cornell Engineering?', '200', 'required', 'Undergraduate');
INSERT INTO public.essay_prompts (title, college_name, how_many, selection_type, prompt_number, prompt, word_limit, prompt_selection_type, school_program_type) VALUES ('Cornell University - Prompt College of Engineering - Short Answer 1', 'Cornell University', 'all', 'required', 'College of Engineering - Short Answer 1', 'What brings you joy?', '100', 'required', 'Undergraduate');
INSERT INTO public.essay_prompts (title, college_name, how_many, selection_type, prompt_number, prompt, word_limit, prompt_selection_type, school_program_type) VALUES ('Cornell University - Prompt College of Engineering - Short Answer 2', 'Cornell University', 'all', 'required', 'College of Engineering - Short Answer 2', 'What do you believe you will contribute to the Cornell Engineering community beyond what you''ve already detailed in your application? What unique voice will you bring?', '100', 'required', 'Undergraduate');
INSERT INTO public.essay_prompts (title, college_name, how_many, selection_type, prompt_number, prompt, word_limit, prompt_selection_type, school_program_type) VALUES ('Cornell University - Prompt College of Engineering - Short Answer 3', 'Cornell University', 'all', 'required', 'College of Engineering - Short Answer 3', 'What is one activity, club, team, organization, work/volunteer experience or family responsibility that is especially meaningful to you? Please briefly tell us about its significance for you.', '100', 'required', 'Undergraduate');
INSERT INTO public.essay_prompts (title, college_name, how_many, selection_type, prompt_number, prompt, word_limit, prompt_selection_type, school_program_type) VALUES ('Cornell University - Prompt College of Engineering - Short Answer 4', 'Cornell University', 'all', 'required', 'College of Engineering - Short Answer 4', 'What is one award you have received or achievement you have attained that has meant the most to you? Please briefly describe its importance to you.', '100', 'required', 'Undergraduate');
INSERT INTO public.essay_prompts (title, college_name, how_many, selection_type, prompt_number, prompt, word_limit, prompt_selection_type, school_program_type) VALUES ('Cornell University - Prompt College of Human Ecology', 'Cornell University', 'all', 'required', 'College of Human Ecology', 'Identify a challenge in your greater community or in the career/industry in which you are interested. Share how the CHE education, your CHE major of choice, as well as the breadth of CHE majors, will help you address that challenge.', '600', 'required', 'Undergraduate');
INSERT INTO public.essay_prompts (title, college_name, how_many, selection_type, prompt_number, prompt, word_limit, prompt_selection_type, school_program_type) VALUES ('Cornell University - Prompt School of Industrial and Labor Relations', 'Cornell University', 'all', 'required', 'School of Industrial and Labor Relations', 'Using your personal, academic, or volunteer/work experiences, describe the topics or issues that you care about and why they are important to you. Your response should show us that your interests align with the ILR School.', '650', 'required', 'Undergraduate');
INSERT INTO public.essay_prompts (title, college_name, how_many, selection_type, prompt_number, prompt, word_limit, prompt_selection_type, school_program_type) VALUES ('Dartmouth College - Prompt 1', 'Dartmouth College', 'all', 'required', '1', 'As you seek admission to Dartmouth''s Class of 2030, what aspects of the college''s academic program, community, and/or campus environment attract your interest? How is Dartmouth a good fit for you?', '100', 'required', 'Undergraduate');
INSERT INTO public.essay_prompts (title, college_name, how_many, selection_type, prompt_number, prompt, word_limit, prompt_selection_type, school_program_type) VALUES ('Dartmouth College - Prompt 2A', 'Dartmouth College', 'all', 'required', '2A', 'There is a Quaker saying: Let your life speak. Describe the environment in which you were raised and the impact it has had on the person you are today.', '250', 'choose_one', 'Undergraduate');
INSERT INTO public.essay_prompts (title, college_name, how_many, selection_type, prompt_number, prompt, word_limit, prompt_selection_type, school_program_type) VALUES ('Dartmouth College - Prompt 2B', 'Dartmouth College', 'all', 'required', '2B', '"Be yourself," Oscar Wilde advised. "Everyone else is taken." Introduce yourself.', '250', 'choose_one', 'Undergraduate');
INSERT INTO public.essay_prompts (title, college_name, how_many, selection_type, prompt_number, prompt, word_limit, prompt_selection_type, school_program_type) VALUES ('Dartmouth College - Prompt 3A', 'Dartmouth College', 'all', 'required', '3A', 'What excites you?', '250', 'choose_one', 'Undergraduate');
INSERT INTO public.essay_prompts (title, college_name, how_many, selection_type, prompt_number, prompt, word_limit, prompt_selection_type, school_program_type) VALUES ('Dartmouth College - Prompt 3B', 'Dartmouth College', 'all', 'required', '3B', 'Labor leader and civil rights activist Dolores Huerta recommended a life of purpose. "We must use our lives to make the world a better place to live, not just to acquire things," she said. "That is what we are put on the earth for." In what ways do you hope to make—or are you already making—an impact? Why? How?', '250', 'choose_one', 'Undergraduate');
INSERT INTO public.essay_prompts (title, college_name, how_many, selection_type, prompt_number, prompt, word_limit, prompt_selection_type, school_program_type) VALUES ('Dartmouth College - Prompt 3C', 'Dartmouth College', 'all', 'required', '3C', 'In an Instagram post, best-selling British author Matt Haig cheered the impact of reading. "A good novel is the best invention humans have ever created for imagining other lives," he wrote. How have you experienced such insight from reading? What did you read and how did it alter the way you understand yourself and others?', '250', 'choose_one', 'Undergraduate');
INSERT INTO public.essay_prompts (title, college_name, how_many, selection_type, prompt_number, prompt, word_limit, prompt_selection_type, school_program_type) VALUES ('Dartmouth College - Prompt 3D', 'Dartmouth College', 'all', 'required', '3D', 'The social and family interactions of wild chimpanzees have been the focus of Dame Jane Goodall''s research for decades. Her understanding of animal behavior prompted the English primatologist to see a lesson for human communities as well: "Change happens by listening and then starting a dialogue with the people who are doing something you don''t believe is right." Channel Dame Goodall: Tell us about a moment when you engaged in a difficult conversation or encountered someone with an opinion or perspective that was different from your own. How did you find common ground?', '250', 'choose_one', 'Undergraduate');
INSERT INTO public.essay_prompts (title, college_name, how_many, selection_type, prompt_number, prompt, word_limit, prompt_selection_type, school_program_type) VALUES ('Dartmouth College - Prompt 3E', 'Dartmouth College', 'all', 'required', '3E', 'Celebrate your nerdy side.', '250', 'choose_one', 'Undergraduate');
INSERT INTO public.essay_prompts (title, college_name, how_many, selection_type, prompt_number, prompt, word_limit, prompt_selection_type, school_program_type) VALUES ('Dartmouth College - Prompt 3F', 'Dartmouth College', 'all', 'required', '3F', '"It''s not easy being green…" was the frequent refrain of Kermit the Frog. How has difference been a part of your life, and how have you embraced it as part of your identity, outlook, or sense of purpose?', '250', 'choose_one', 'Undergraduate');
INSERT INTO public.essay_prompts (title, college_name, how_many, selection_type, prompt_number, prompt, word_limit, prompt_selection_type, school_program_type) VALUES ('Dartmouth College - Prompt 3G', 'Dartmouth College', 'all', 'required', '3G', 'The Mindy Kaling Theater Lab will be an exciting new addition to Dartmouth''s Hopkins Center for the Arts. "It''s a place where you can fail," the actor/producer and Dartmouth alumna said when her gift was announced. "You can try things out, fail, and then revamp and rework things… A thing can be bad on its journey to becoming good." Share a story of failure, trial runs, revamping, reworking, or journeying from bad to good.', '250', 'choose_one', 'Undergraduate');
INSERT INTO public.essay_prompts (title, college_name, how_many, selection_type, prompt_number, prompt, word_limit, prompt_selection_type, school_program_type) VALUES ('University of Chicago - Prompt 1', 'University of Chicago', 'all', 'required', '1', 'How does the University of Chicago, as you know it now, satisfy your desire for a particular kind of learning, community, and future? Please address with some specificity your own wishes and how they relate to UChicago.', 'Not specified', 'required', 'Undergraduate');
INSERT INTO public.essay_prompts (title, college_name, how_many, selection_type, prompt_number, prompt, word_limit, prompt_selection_type, school_program_type) VALUES ('University of Chicago - Prompt 2', 'University of Chicago', 'all', 'required', '2', 'In an ideal world where inter-species telepathic communication exists, which species would you choose to have a conversation with, and what would you want to learn from them? Would you ask beavers for architectural advice? Octopuses about cognition? Pigeons about navigation? Ants about governance? Make your case—both for the species and the question.', 'Not specified', 'choose_one', 'Undergraduate');
INSERT INTO public.essay_prompts (title, college_name, how_many, selection_type, prompt_number, prompt, word_limit, prompt_selection_type, school_program_type) VALUES ('University of Chicago - Prompt 3', 'University of Chicago', 'all', 'required', '3', 'If you could uninvent one thing, what would it be — and what would unravel as a result?', 'Not specified', 'choose_one', 'Undergraduate');
INSERT INTO public.essay_prompts (title, college_name, how_many, selection_type, prompt_number, prompt, word_limit, prompt_selection_type, school_program_type) VALUES ('University of Chicago - Prompt 4', 'University of Chicago', 'all', 'required', '4', '"Left" can mean remaining or departed. "Dust" can mean to add fine particles or to remove them. "Fast" can mean moving quickly or fixed firmly in place. These contronyms—words that are their own antonyms—somehow hold opposing meanings in perfect tension. Explore a contronym: a role, identity, or experience in your life that has contained its own opposite.', 'Not specified', 'choose_one', 'Undergraduate');
INSERT INTO public.essay_prompts (title, college_name, how_many, selection_type, prompt_number, prompt, word_limit, prompt_selection_type, school_program_type) VALUES ('University of Chicago - Prompt 5', 'University of Chicago', 'all', 'required', '5', 'The penny is on its way out—too small to matter, too costly to keep. But not everything small should disappear. What''s one object the world is phasing out that you think we can''t afford to lose, and why?', 'Not specified', 'choose_one', 'Undergraduate');
INSERT INTO public.essay_prompts (title, college_name, how_many, selection_type, prompt_number, prompt, word_limit, prompt_selection_type, school_program_type) VALUES ('University of Chicago - Prompt 6', 'University of Chicago', 'all', 'required', '6', 'From Michelin Tires creating the Michelin Guide, to the audio equipment company Audio-Technica becoming one of the world''s largest manufacturers of sushi robots, brand identity can turn out to be a lot more flexible than we think. Choose an existing brand, company, or institution and propose an unexpected but strangely logical new product or service for them to launch. Why is this unlikely extension exactly what the world (or the brand) needs right now?', 'Not specified', 'choose_one', 'Undergraduate');
INSERT INTO public.essay_prompts (title, college_name, how_many, selection_type, prompt_number, prompt, word_limit, prompt_selection_type, school_program_type) VALUES ('University of Chicago - Prompt 7', 'University of Chicago', 'all', 'required', '7', 'Statistically speaking, ice cream doesn''t cause shark attacks, pet spending doesn''t drive the number of lawyers in California, and margarine consumption isn''t responsible for Maine''s divorce rate—at least, not according to conventional wisdom. But what if the statisticians got it wrong? Choose your favorite spurious correlation and make the case for why it might actually reveal a deeper, causative truth.', 'Not specified', 'choose_one', 'Undergraduate');
INSERT INTO public.essay_prompts (title, college_name, how_many, selection_type, prompt_number, prompt, word_limit, prompt_selection_type, school_program_type) VALUES ('University of Chicago - Prompt 8', 'University of Chicago', 'all', 'required', '8', 'And, as always… the classic choose your own adventure option! In the spirit of adventurous inquiry, choose one of our past prompts (or create a question of your own). Be original, creative, thought provoking. Draw on your best qualities as a writer, thinker, visionary, social critic, sage, citizen of the world, or future citizen of the University of Chicago; take a little risk and have fun!', 'Not specified', 'choose_one', 'Undergraduate');
INSERT INTO public.essay_prompts (title, college_name, how_many, selection_type, prompt_number, prompt, word_limit, prompt_selection_type, school_program_type) VALUES ('University of California - Prompt 1', 'University of California', 'four', 'choose_four', '1', 'Describe an example of your leadership experience in which you have positively influenced others, helped resolve disputes or contributed to group efforts over time.', '350', 'choose_four', 'Undergraduate');
INSERT INTO public.essay_prompts (title, college_name, how_many, selection_type, prompt_number, prompt, word_limit, prompt_selection_type, school_program_type) VALUES ('University of California - Prompt 2', 'University of California', 'four', 'choose_four', '2', 'Every person has a creative side, and it can be expressed in many ways: problem solving, original and innovative thinking, and artistically, to name a few. Describe how you express your creative side.', '350', 'choose_four', 'Undergraduate');
INSERT INTO public.essay_prompts (title, college_name, how_many, selection_type, prompt_number, prompt, word_limit, prompt_selection_type, school_program_type) VALUES ('University of California - Prompt 3', 'University of California', 'four', 'choose_four', '3', 'What would you say is your greatest talent or skill? How have you developed and demonstrated that talent over time?', '350', 'choose_four', 'Undergraduate');
INSERT INTO public.essay_prompts (title, college_name, how_many, selection_type, prompt_number, prompt, word_limit, prompt_selection_type, school_program_type) VALUES ('University of California - Prompt 4', 'University of California', 'four', 'choose_four', '4', 'Describe how you have taken advantage of a significant educational opportunity or worked to overcome an educational barrier you have faced.', '350', 'choose_four', 'Undergraduate');
INSERT INTO public.essay_prompts (title, college_name, how_many, selection_type, prompt_number, prompt, word_limit, prompt_selection_type, school_program_type) VALUES ('University of California - Prompt 5', 'University of California', 'four', 'choose_four', '5', 'Describe the most significant challenge you have faced and the steps you have taken to overcome this challenge. How has this challenge affected your academic achievement?', '350', 'choose_four', 'Undergraduate');
INSERT INTO public.essay_prompts (title, college_name, how_many, selection_type, prompt_number, prompt, word_limit, prompt_selection_type, school_program_type) VALUES ('University of California - Prompt 6', 'University of California', 'four', 'choose_four', '6', 'Think about an academic subject that inspires you. Describe how you have furthered this interest inside and/or outside of the classroom.', '350', 'choose_four', 'Undergraduate');
INSERT INTO public.essay_prompts (title, college_name, how_many, selection_type, prompt_number, prompt, word_limit, prompt_selection_type, school_program_type) VALUES ('University of California - Prompt 7', 'University of California', 'four', 'choose_four', '7', 'What have you done to make your school or your community a better place?', '350', 'choose_four', 'Undergraduate');
INSERT INTO public.essay_prompts (title, college_name, how_many, selection_type, prompt_number, prompt, word_limit, prompt_selection_type, school_program_type) VALUES ('University of California - Prompt 8', 'University of California', 'four', 'choose_four', '8', 'Beyond what has already been shared in your application, what do you believe makes you a strong candidate for admission to the University of California?', '350', 'choose_four', 'Undergraduate');
INSERT INTO public.essay_prompts (title, college_name, how_many, selection_type, prompt_number, prompt, word_limit, prompt_selection_type, school_program_type) VALUES ('Rice University - Prompt 1', 'Rice University', 'all', 'required', '1', 'Please explain why you wish to study in the academic areas you selected.', '150', 'required', 'Undergraduate');
INSERT INTO public.essay_prompts (title, college_name, how_many, selection_type, prompt_number, prompt, word_limit, prompt_selection_type, school_program_type) VALUES ('Rice University - Prompt 2', 'Rice University', 'all', 'required', '2', 'Based upon your exploration of Rice University, what elements of the Rice experience appeal to you?', '150', 'required', 'Undergraduate');
INSERT INTO public.essay_prompts (title, college_name, how_many, selection_type, prompt_number, prompt, word_limit, prompt_selection_type, school_program_type) VALUES ('Rice University - Prompt 3A', 'Rice University', 'all', 'required', '3A', 'The Residential College System is at the heart of Rice student life and is heavily influenced by the particular cultural traditions and unique life experiences each student brings. What life experiences and/or unique perspectives are you looking forward to sharing with fellow Owls in the residential college system?', '500', 'choose_one', 'Undergraduate');
INSERT INTO public.essay_prompts (title, college_name, how_many, selection_type, prompt_number, prompt, word_limit, prompt_selection_type, school_program_type) VALUES ('Rice University - Prompt 3B', 'Rice University', 'all', 'required', '3B', 'Rice is strengthened by its diverse community of learning and discovery that produces leaders and change agents across the spectrum of human endeavor. What perspectives shaped by your background, experiences, upbringing, and/or cultural identity inspire you to join our community of change agents at Rice?', '500', 'choose_one', 'Undergraduate');
INSERT INTO public.essay_prompts (title, college_name, how_many, selection_type, prompt_number, prompt, word_limit, prompt_selection_type, school_program_type) VALUES ('Rice University - Prompt Rice Box', 'Rice University', 'all', 'required', 'Rice Box', 'One of Rice''s long-standing traditions is "The Box," a question on our application where we ask all of our applicants to share an image of something that appeals to them. The Box gives you the opportunity to present us with an image that shares something about yourself, your interests or what is meaningful to you. This image is not used for evaluative purposes in the application, but allows you to put your stamp on the application about who you are aside from what you have achieved. Be sure to choose an image that speaks for itself and does not need an explanation. The Box must be a two-dimensional image that is uploaded in the Common Application or uploaded in the Rice Admission Student Portal.', 'Image upload', 'required', 'Undergraduate');
INSERT INTO public.essay_prompts (title, college_name, how_many, selection_type, prompt_number, prompt, word_limit, prompt_selection_type, school_program_type) VALUES ('University of Notre Dame - Prompt 1', 'University of Notre Dame', 'all', 'required', '1', 'Many students have multiple areas of study that they consider before declaring a major at Notre Dame. We invite you to share up to two additional majors that you are considering. Briefly share what draws you to the area(s) of study you listed.', '100', 'required', 'Undergraduate');
INSERT INTO public.essay_prompts (title, college_name, how_many, selection_type, prompt_number, prompt, word_limit, prompt_selection_type, school_program_type) VALUES ('University of Notre Dame - Prompt 2', 'University of Notre Dame', 'all', 'required', '2', 'Everyone has different priorities when considering their higher education options and building their college or university list. Tell us about your "non-negotiable" factor(s) when searching for your future college home.', '150', 'required', 'Undergraduate');
INSERT INTO public.essay_prompts (title, college_name, how_many, selection_type, prompt_number, prompt, word_limit, prompt_selection_type, school_program_type) VALUES ('University of Notre Dame - Prompt 3', 'University of Notre Dame', 'all', 'required', '3', 'How does faith influence the decisions you make?', '50-100', 'choose_three', 'Undergraduate');
INSERT INTO public.essay_prompts (title, college_name, how_many, selection_type, prompt_number, prompt, word_limit, prompt_selection_type, school_program_type) VALUES ('University of Notre Dame - Prompt 4', 'University of Notre Dame', 'all', 'required', '4', 'What is distinctive about your personal experiences and development (eg, family support, culture, disability, personal background, community)? Why are these experiences important to you and how will you enrich the Notre Dame community?', '50-100', 'choose_three', 'Undergraduate');
INSERT INTO public.essay_prompts (title, college_name, how_many, selection_type, prompt_number, prompt, word_limit, prompt_selection_type, school_program_type) VALUES ('University of Notre Dame - Prompt 5', 'University of Notre Dame', 'all', 'required', '5', 'Notre Dame''s undergraduate experience is characterized by a collective sense of care for every person. How do you foster service to others in your community?', '50-100', 'choose_three', 'Undergraduate');
INSERT INTO public.essay_prompts (title, college_name, how_many, selection_type, prompt_number, prompt, word_limit, prompt_selection_type, school_program_type) VALUES ('University of Notre Dame - Prompt 6', 'University of Notre Dame', 'all', 'required', '6', 'What compliment are you most proud of receiving, and why does it mean so much to you?', '50-100', 'choose_three', 'Undergraduate');
INSERT INTO public.essay_prompts (title, college_name, how_many, selection_type, prompt_number, prompt, word_limit, prompt_selection_type, school_program_type) VALUES ('University of Notre Dame - Prompt 7', 'University of Notre Dame', 'all', 'required', '7', 'What would you fight for?', '50-100', 'choose_three', 'Undergraduate');
INSERT INTO public.essay_prompts (title, college_name, how_many, selection_type, prompt_number, prompt, word_limit, prompt_selection_type, school_program_type) VALUES ('Vanderbilt University - Prompt 1', 'Vanderbilt University', 'one', 'required', '1', 'Vanderbilt University''s motto, Crescere aude, is Latin for "dare to grow." In your response, reflect on how one or more aspects of your identity, culture, or background has played a role in your personal growth, and how it will contribute to our campus community as you dare to grow at Vanderbilt.', '250', 'required', 'Undergraduate');
INSERT INTO public.essay_prompts (title, college_name, how_many, selection_type, prompt_number, prompt, word_limit, prompt_selection_type, school_program_type) VALUES ('University of Michigan - Prompt 1', 'University of Michigan', 'all', 'required', '1', 'At the University of Michigan, we are focused on developing leaders and citizens who will challenge the present and enrich the future. In your essay, share with us how you are prepared to contribute to these goals. This could include the people, places, experiences, or aspirations that have shaped your journey and future plans.', '100-300', 'required', 'Undergraduate');
INSERT INTO public.essay_prompts (title, college_name, how_many, selection_type, prompt_number, prompt, word_limit, prompt_selection_type, school_program_type) VALUES ('University of Michigan - Prompt 2', 'University of Michigan', 'all', 'required', '2', 'Describe the unique qualities that attract you to the specific undergraduate college or school (including preferred admission and dual degree programs) to which you are applying at the University of Michigan. How would that curriculum support your interests?', '100-500', 'required', 'Undergraduate');
INSERT INTO public.essay_prompts (title, college_name, how_many, selection_type, prompt_number, prompt, word_limit, prompt_selection_type, school_program_type) VALUES ('Washington University in St. Louis - Prompt 1', 'Washington University in St. Louis', 'one', 'required', '1', 'Please tell us what you are interested in studying at college and why.
INSERT INTO public.essay_prompts (title, college_name, how_many, selection_type, prompt_number, prompt, word_limit, prompt_selection_type, school_program_type) VALUES ('Washington University in St. Louis - Prompt 2A', 'Washington University in St. Louis', 'one', 'required', '2A', 'WashU supports engagement in the St. Louis community by considering the university as "In St. Louis, For St. Louis." What is a community you are a part of and your place or impact within it?', '250', 'choose_one', 'Undergraduate');
INSERT INTO public.essay_prompts (title, college_name, how_many, selection_type, prompt_number, prompt, word_limit, prompt_selection_type, school_program_type) VALUES ('Washington University in St. Louis - Prompt 2B', 'Washington University in St. Louis', 'one', 'required', '2B', 'WashU strives to know every undergraduate student "By Name & Story." How have your life experiences shaped your story?', '250', 'choose_one', 'Undergraduate');
INSERT INTO public.essay_prompts (title, college_name, how_many, selection_type, prompt_number, prompt, word_limit, prompt_selection_type, school_program_type) VALUES ('Emory University - Prompt 1', 'Emory University', 'one', 'required', '1', 'What academic areas are you interested in exploring at Emory University and why?', '200', 'required', 'Undergraduate');
INSERT INTO public.essay_prompts (title, college_name, how_many, selection_type, prompt_number, prompt, word_limit, prompt_selection_type, school_program_type) VALUES ('Emory University - Prompt 2A', 'Emory University', 'one', 'required', '2A', 'Emory University has a strong commitment to building community. Tell us about a community that you have been part of where your personal participation helped to change or shape the community for the better.', '150', 'choose_one', 'Undergraduate');
INSERT INTO public.essay_prompts (title, college_name, how_many, selection_type, prompt_number, prompt, word_limit, prompt_selection_type, school_program_type) VALUES ('Emory University - Prompt 2B', 'Emory University', 'one', 'required', '2B', 'Reflect on a personal experience where you intentionally expanded your cultural awareness.', '150', 'choose_one', 'Undergraduate');
INSERT INTO public.essay_prompts (title, college_name, how_many, selection_type, prompt_number, prompt, word_limit, prompt_selection_type, school_program_type) VALUES ('Emory University - Prompt 2C', 'Emory University', 'one', 'required', '2C', 'Emory University''s unique mission calls for service to humanity. Share how you might personally contribute to this mission of service to humanity.', '150', 'choose_one', 'Undergraduate');
INSERT INTO public.essay_prompts (title, college_name, how_many, selection_type, prompt_number, prompt, word_limit, prompt_selection_type, school_program_type) VALUES ('Emory University - Prompt 2D', 'Emory University', 'one', 'required', '2D', 'In a scholarly community, differing ideas often collide before they converge. How do you personally navigate disagreement in a way that promotes progress and deepens meaningful dialogue?', '150', 'choose_one', 'Undergraduate');
INSERT INTO public.essay_prompts (title, college_name, how_many, selection_type, prompt_number, prompt, word_limit, prompt_selection_type, school_program_type) VALUES ('Georgetown University - Prompt 1', 'Georgetown University', 'all', 'required', '1', 'As Georgetown is a diverse community, the Admissions Committee would like to know more about you in your own words. Please submit a brief personal or creative essay which you feel best describes you and reflects on your own background, identity, skills, and talents.', 'One page', 'required', 'Undergraduate');
INSERT INTO public.essay_prompts (title, college_name, how_many, selection_type, prompt_number, prompt, word_limit, prompt_selection_type, school_program_type) VALUES ('Georgetown University - Prompt College of Arts & Sciences', 'Georgetown University', 'all', 'required', 'College of Arts & Sciences', 'Founded in 1789, the Georgetown College of Arts & Sciences is committed to the Jesuit traditions of an integrated education and of productive research in the natural sciences, humanities, social sciences, and fine arts. Describe your interest in studying at College of Arts & Sciences. Applicants interested in the sciences, mathematics, or languages are encouraged to make specific reference to their choice of major.', 'One page', 'required', 'Undergraduate');
INSERT INTO public.essay_prompts (title, college_name, how_many, selection_type, prompt_number, prompt, word_limit, prompt_selection_type, school_program_type) VALUES ('Georgetown University - Prompt School of Nursing', 'Georgetown University', 'all', 'required', 'School of Nursing', 'Georgetown University''s School of Nursing is committed to the formation of ethical, empathetic, and transformational nursing leaders. Describe the factors that have influenced your interest in studying Nursing at Georgetown University.', 'One page', 'required', 'Undergraduate');
INSERT INTO public.essay_prompts (title, college_name, how_many, selection_type, prompt_number, prompt, word_limit, prompt_selection_type, school_program_type) VALUES ('Georgetown University - Prompt School of Health', 'Georgetown University', 'all', 'required', 'School of Health', 'Georgetown University''s School of Health was founded to advance the health and well-being of people locally, nationally, and globally through innovative research, the delivery of interdisciplinary education, and transformative engagement of communities. Describe the factors that influenced your interest in studying health care at Georgetown University, specifically addressing your intended related major: Global Health, Health Care Management & Policy, or Human Science.', 'One page', 'required', 'Undergraduate');
INSERT INTO public.essay_prompts (title, college_name, how_many, selection_type, prompt_number, prompt, word_limit, prompt_selection_type, school_program_type) VALUES ('Georgetown University - Prompt Walsh School of Foreign Service', 'Georgetown University', 'all', 'required', 'Walsh School of Foreign Service', 'Georgetown University''s Walsh School of Foreign Service was founded more than a century ago to prepare generations of leaders with the foundational skills to address global issues. Describe your primary motivations for studying international affairs at Georgetown University and dedicating your undergraduate studies toward a future in global service.', 'One page', 'required', 'Undergraduate');
INSERT INTO public.essay_prompts (title, college_name, how_many, selection_type, prompt_number, prompt, word_limit, prompt_selection_type, school_program_type) VALUES ('Georgetown University - Prompt McDonough School of Business', 'Georgetown University', 'all', 'required', 'McDonough School of Business', 'Georgetown University''s McDonough School of Business provides graduates with essential global, ethical, analytical, financial, and diverse perspectives on the economies of our nation and the world. Describe your primary motivations for studying business at Georgetown University.', 'One page', 'required', 'Undergraduate');
INSERT INTO public.essay_prompts (title, college_name, how_many, selection_type, prompt_number, prompt, word_limit, prompt_selection_type, school_program_type) VALUES ('Georgetown University - Prompt McCourt School of Public Policy', 'Georgetown University', 'all', 'required', 'McCourt School of Public Policy', 'For nearly 50 years, Georgetown University''s McCourt School of Public Policy has equipped leaders and changemakers with the interdisciplinary skills to address local, national and global policy problems. Undergraduate public policy students at Georgetown will have the unique opportunity to live and study on two campuses, spending their first two years immersed on the Hilltop, before completing the second half of their time at Georgetown on the Capitol Campus, immersed in the policy world. Describe your primary motivations for studying public policy at Georgetown University and dedicating your undergraduate studies toward a future related to public service.', 'One page', 'required', 'Undergraduate');
INSERT INTO public.essay_prompts (title, college_name, how_many, selection_type, prompt_number, prompt, word_limit, prompt_selection_type, school_program_type) VALUES ('Georgetown University - Prompt Special Talents or Skills', 'Georgetown University', 'all', 'required', 'Special Talents or Skills', 'Please indicate any special talents or skills you possess. You should write in either paragraph or bulleted-list format.', '250', 'required', 'Undergraduate');
INSERT INTO public.essay_prompts (title, college_name, how_many, selection_type, prompt_number, prompt, word_limit, prompt_selection_type, school_program_type) VALUES ('Georgia Institute of Technology - Prompt 1', 'Georgia Institute of Technology', 'one', 'required', '1', 'Why do you want to study your chosen major, and why do you want to study that major at Georgia Tech?', '300', 'required', 'Undergraduate');
INSERT INTO public.essay_prompts (title, college_name, how_many, selection_type, prompt_number, prompt, word_limit, prompt_selection_type, school_program_type) VALUES ('University of North Carolina - Prompt 1', 'University of North Carolina', 'all', 'required', '1', 'Discuss one of your personal qualities and share a story, anecdote, or memory of how it helped you make a positive impact on a community. This could be your current community or another community you have engaged.', '250', 'required', 'Undergraduate');
INSERT INTO public.essay_prompts (title, college_name, how_many, selection_type, prompt_number, prompt, word_limit, prompt_selection_type, school_program_type) VALUES ('University of North Carolina - Prompt 2', 'University of North Carolina', 'all', 'required', '2', 'Discuss an academic topic that you''re excited to explore and learn more about in college. Why does this topic interest you? Topics could be a specific course of study, research interests, or any other area related to your academic experience in college.', '250', 'required', 'Undergraduate');
INSERT INTO public.essay_prompts (title, college_name, how_many, selection_type, prompt_number, prompt, word_limit, prompt_selection_type, school_program_type) VALUES ('University of Massachusetts Amherst - Prompt 1', 'University of Massachusetts Amherst', 'one', 'required', '1', 'Please tell us why you chose the Major(s) you did.', '100', 'required', 'Undergraduate');
INSERT INTO public.essay_prompts (title, college_name, how_many, selection_type, prompt_number, prompt, word_limit, prompt_selection_type, school_program_type) VALUES ('University of Georgia - Prompt 1', 'University of Georgia', 'one', 'required', '1', 'The transition from middle to high school is a key time for students as they reach new levels of both academic and personal discovery. Please share a book (novel, non-fiction, etc.) that had a serious impact on you during this time. Please focus more on why this book made an impact on you and less on the plot/theme of the book itself (we are not looking for a book report).
INSERT INTO public.essay_prompts (title, college_name, how_many, selection_type, prompt_number, prompt, word_limit, prompt_selection_type, school_program_type) VALUES ('University of Texas - Prompt 1', 'University of Texas', 'two', 'required', '1', 'Why are you interested in the major you indicated as your first-choice major?', '250-300', 'required', 'Undergraduate');
INSERT INTO public.essay_prompts (title, college_name, how_many, selection_type, prompt_number, prompt, word_limit, prompt_selection_type, school_program_type) VALUES ('University of Texas - Prompt 2', 'University of Texas', 'two', 'required', '2', 'Think of all the activities — both in and outside of school — that you have been involved with during high school. Which one are you most proud of and why? (Guidance for students: This can include an extracurricular activity, a club/organization, volunteer activity, work or a family responsibility.)', '250-300', 'required', 'Undergraduate');
INSERT INTO public.essay_prompts (title, college_name, how_many, selection_type, prompt_number, prompt, word_limit, prompt_selection_type, school_program_type) VALUES ('University of Texas - Prompt 3', 'University of Texas', 'two', 'required', '3', 'Please share background on events or special circumstances that you feel may have impacted your high school academic performance.', '250-300', 'optional', 'Undergraduate');
INSERT INTO public.essay_prompts (title, college_name, how_many, selection_type, prompt_number, prompt, word_limit, prompt_selection_type, school_program_type) VALUES ('University of Southern California - Prompt 1', 'University of Southern California', 'all', 'required', '1', 'Describe how you plan to pursue your academic interests and why you want to explore them at USC specifically. Please feel free to address your first- and second-choice major selections.', '250', 'required', 'Undergraduate');
INSERT INTO public.essay_prompts (title, college_name, how_many, selection_type, prompt_number, prompt, word_limit, prompt_selection_type, school_program_type) VALUES ('University of Southern California - Prompt 2', 'University of Southern California', 'all', 'required', '2', 'Starting with the beginning of high school/secondary school, if you have had a gap where you were not enrolled in school during a fall or spring term, please address this gap in your educational history. You do not need to address a summer break.', 'Not specified', 'required', 'Undergraduate');
INSERT INTO public.essay_prompts (title, college_name, how_many, selection_type, prompt_number, prompt, word_limit, prompt_selection_type, school_program_type) VALUES ('University of Southern California - Prompt 3', 'University of Southern California', 'all', 'required', '3', 'Describe yourself in three words.
INSERT INTO public.essay_prompts (title, college_name, how_many, selection_type, prompt_number, prompt, word_limit, prompt_selection_type, school_program_type) VALUES ('University of Southern California - Prompt 4', 'University of Southern California', 'all', 'required', '4', 'What is your favorite snack?', 'Not specified', 'required', 'Undergraduate');
INSERT INTO public.essay_prompts (title, college_name, how_many, selection_type, prompt_number, prompt, word_limit, prompt_selection_type, school_program_type) VALUES ('University of Southern California - Prompt 5', 'University of Southern California', 'all', 'required', '5', 'Best movie of all time:', 'Not specified', 'required', 'Undergraduate');
