INSERT INTO public.essay_prompts (title, college_name, how_many, selection_type, prompt_number, prompt, word_limit, prompt_selection_type, school_program_type) VALUES ('University of Southern California - Prompt 9', 'University of Southern California', 'all', 'required', '9', 'What TV show will you binge watch next?', 'Not specified', 'required', 'Undergraduate');
INSERT INTO public.essay_prompts (title, college_name, how_many, selection_type, prompt_number, prompt, word_limit, prompt_selection_type, school_program_type) VALUES ('University of Southern California - Prompt 10', 'University of Southern California', 'all', 'required', '10', 'Which well-known person or fictional character would be your ideal roommate?', 'Not specified', 'required', 'Undergraduate');
