INSERT INTO public.essay_prompts (title, college_name, how_many, selection_type, prompt_number, prompt, word_limit, prompt_selection_type, school_program_type) VALUES ('University of Southern California - Prompt 12', 'University of Southern California', 'all', 'required', '12', 'If you could teach a class on any topic, what would it be?', 'Not specified', 'required', 'Undergraduate');
INSERT INTO public.essay_prompts (title, college_name, how_many, selection_type, prompt_number, prompt, word_limit, prompt_selection_type, school_program_type) VALUES ('University of Virginia - Prompt School of Nursing', 'University of Virginia', 'one', 'required', 'School of Nursing', 'Describe a health care-related experience or another significant interaction that deepened your interest in studying Nursing.', '300', 'required', 'Undergraduate');
INSERT INTO public.essay_prompts (title, college_name, how_many, selection_type, prompt_number, prompt, word_limit, prompt_selection_type, school_program_type) VALUES ('New York University - Prompt 1', 'New York University', 'one', 'required', '1', 'We are looking for students who want to be bridge builders—students who can connect people, groups, and ideas to span divides, foster understanding, and promote collaboration within a dynamic, interconnected, and vibrant global academic community. We are eager for you to tell us how your experiences have helped you understand what qualities and efforts are needed to bridge divides so that people can better learn and work together.
INSERT INTO public.essay_prompts (title, college_name, how_many, selection_type, prompt_number, prompt, word_limit, prompt_selection_type, school_program_type) VALUES ('University of Arizona - Prompt 1', 'University of Arizona', 'one', 'required', '1', 'Why is the University of Arizona the right fit for you and how will your chosen academic area of study align with your interests, goals, and values?', '500', 'required', 'Undergraduate');
INSERT INTO public.essay_prompts (title, college_name, how_many, selection_type, prompt_number, prompt, word_limit, prompt_selection_type, school_program_type) VALUES ('University of Wisconsin-Madison - Prompt 1', 'University of Wisconsin-Madison', 'one', 'required', '1', 'Tell us why you would like to attend the University of Wisconsin–Madison. In addition, please include why you are interested in studying the major(s) you have selected. If you selected undecided, please describe your areas of possible academic interest.', '650', 'required', 'Undergraduate');
INSERT INTO public.essay_prompts (title, college_name, how_many, selection_type, prompt_number, prompt, word_limit, prompt_selection_type, school_program_type) VALUES ('Harvard Business School - Prompt 1', 'Harvard Business School', '1', 'required', '1', 'Harvard Business School''s mission is to educate leaders who make a difference in the world. How do you plan to make a difference in the world after you graduate?', '400', 'required', 'MBA');
INSERT INTO public.essay_prompts (title, college_name, how_many, selection_type, prompt_number, prompt, word_limit, prompt_selection_type, school_program_type) VALUES ('Stanford Graduate School of Business - Prompt 1', 'Stanford Graduate School of Business', '1', 'required', '1', 'What matters most to you, and why?', '650', 'required', 'MBA');
INSERT INTO public.essay_prompts (title, college_name, how_many, selection_type, prompt_number, prompt, word_limit, prompt_selection_type, school_program_type) VALUES ('Stanford Graduate School of Business - Prompt 2', 'Stanford Graduate School of Business', '1', 'required', '2', 'Why Stanford?', '400', 'required', 'MBA');
INSERT INTO public.essay_prompts (title, college_name, how_many, selection_type, prompt_number, prompt, word_limit, prompt_selection_type, school_program_type) VALUES ('Wharton School - Prompt 1', 'Wharton School', '1', 'required', '1', 'How do you plan to use the Wharton MBA program to help you achieve your future professional plans?', '500', 'required', 'MBA');
INSERT INTO public.essay_prompts (title, college_name, how_many, selection_type, prompt_number, prompt, word_limit, prompt_selection_type, school_program_type) VALUES ('Wharton School - Prompt 2', 'Wharton School', '1', 'required', '2', 'Taking into consideration your background – personal, professional, and/or academic – how do you plan to make specific, meaningful contributions to the Wharton community?', '400', 'required', 'MBA');
INSERT INTO public.essay_prompts (title, college_name, how_many, selection_type, prompt_number, prompt, word_limit, prompt_selection_type, school_program_type) VALUES ('Kellogg School of Management - Prompt 1', 'Kellogg School of Management', '1', 'required', '1', 'Kellogg''s purpose is to educate, equip and inspire brave leaders who create lasting value. Tell us about a time you have demonstrated leadership and created lasting value. What challenges did you face, and what did you learn?', '450', 'required', 'MBA');
INSERT INTO public.essay_prompts (title, college_name, how_many, selection_type, prompt_number, prompt, word_limit, prompt_selection_type, school_program_type) VALUES ('Kellogg School of Management - Prompt 2', 'Kellogg School of Management', '1', 'required', '2', 'Values are what guide you in your life and work. What values are important to you and how have they influenced you?', '450', 'required', 'MBA');
INSERT INTO public.essay_prompts (title, college_name, how_many, selection_type, prompt_number, prompt, word_limit, prompt_selection_type, school_program_type) VALUES ('MIT Sloan - Prompt 1', 'MIT Sloan', '1', 'required', '1', 'The mission of the MIT Sloan School of Management is to develop principled, innovative leaders who improve the world and to generate ideas that advance management practice. Discuss how you will contribute toward advancing the mission based on examples of past work and activities. (300 words or fewer)', '300', 'required', 'MBA');
INSERT INTO public.essay_prompts (title, college_name, how_many, selection_type, prompt_number, prompt, word_limit, prompt_selection_type, school_program_type) VALUES ('MIT Sloan - Prompt 2', 'MIT Sloan', '1', 'required', '2', 'Describe a time when you went beyond what was defined, expected, or required in your role. What did you do, why did you do it, and what was the outcome? (300 words or fewer)', '300', 'required', 'MBA');
INSERT INTO public.essay_prompts (title, college_name, how_many, selection_type, prompt_number, prompt, word_limit, prompt_selection_type, school_program_type) VALUES ('Chicago Booth - Prompt 1', 'Chicago Booth', '1', 'required', '1', 'How will the Booth MBA help you achieve your immediate and long-term post-MBA career goals? (250 word minimum)', '250', 'required', 'MBA');
INSERT INTO public.essay_prompts (title, college_name, how_many, selection_type, prompt_number, prompt, word_limit, prompt_selection_type, school_program_type) VALUES ('Chicago Booth - Prompt 2', 'Chicago Booth', '1', 'required', '2', 'An MBA is as much about personal growth as it is about professional development. In addition to your career goals, what aspects of your personal development do you hope to develop while at Booth? (250 word minimum)', '250', 'required', 'MBA');
INSERT INTO public.essay_prompts (title, college_name, how_many, selection_type, prompt_number, prompt, word_limit, prompt_selection_type, school_program_type) VALUES ('Columbia Business School - Prompt 1', 'Columbia Business School', '1', 'required', '1', 'Through your resume and recommendations, we have a clear sense of your professional path to date. What are your career goals over the next 3-5 years and what, in your imagination, would be your long-term dream job? (500 words)', '500', 'required', 'MBA');
INSERT INTO public.essay_prompts (title, college_name, how_many, selection_type, prompt_number, prompt, word_limit, prompt_selection_type, school_program_type) VALUES ('Columbia Business School - Prompt 2', 'Columbia Business School', '1', 'required', '2', 'We believe Columbia Business School is a special place. CBS proudly fosters a collaborative and supportive community where students are encouraged to engage with each other and the broader community. Why do you feel Columbia Business School is a good fit for you academically, culturally, and professionally? Please be specific. (250 words)', '250', 'required', 'MBA');